import{_ as a,c as r,o,ah as n}from"./chunks/framework.C-x9UAyH.js";const p=JSON.parse('{"title":"Creación y despliegue de un clúster AKS","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"azure/creacion_aks.md","filePath":"azure/creacion_aks.md","lastUpdated":1760560955000}'),s={name:"azure/creacion_aks.md"};function l(i,e,t,c,d,g){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="creacion-y-despliegue-de-un-cluster-aks" tabindex="-1">Creación y despliegue de un clúster AKS <a class="header-anchor" href="#creacion-y-despliegue-de-un-cluster-aks" aria-label="Permalink to &quot;Creación y despliegue de un clúster AKS&quot;">​</a></h1><h2 id="_1-acceso-a-azure-portal" tabindex="-1">1. Acceso a Azure Portal <a class="header-anchor" href="#_1-acceso-a-azure-portal" aria-label="Permalink to &quot;1. Acceso a Azure Portal&quot;">​</a></h2><ul><li>Ingresar a <a href="https://aka.ms/azureportal" target="_blank" rel="noreferrer">Azure Portal</a>.</li><li>Crear un <strong>nuevo grupo de recursos</strong> para AKS.</li></ul><h2 id="_2-creacion-del-cluster-aks" tabindex="-1">2. Creación del Clúster AKS <a class="header-anchor" href="#_2-creacion-del-cluster-aks" aria-label="Permalink to &quot;2. Creación del Clúster AKS&quot;">​</a></h2><ol><li><p><strong>Iniciar la Creación</strong>:</p><ul><li>📌 En el menú o búsqueda de Azure Portal, localizar el <strong>Servicio de Kubernetes (AKS)</strong>.</li><li>🖱️ Hacer clic en <strong>Crear clúster de Kubernetes</strong>.</li></ul></li><li><p><strong>Configuración Básica</strong> ⚙️:</p><ul><li><strong>Suscripción</strong>: Seleccionar <strong>Azure for Students</strong>. ✅</li><li><strong>Grupo de recursos</strong>: Elegir el grupo de recursos creado previamente. 🗂️</li><li><strong>Nombre del clúster</strong>: Asignar un nombre único para el clúster AKS. ✏️</li><li><strong>Región</strong>: Seleccionar <strong>East US 2</strong> como región. 🌎</li><li><strong>Otros ajustes</strong>: Dejar los valores predeterminados y hacer click en <strong>Siguiente</strong>. ➡️</li></ul></li><li><p><strong>Configuración de Grupos de Nodos</strong> 🖥️:</p><ul><li><strong>Agentpool Predeterminado</strong>: <ul><li>Seleccionar el <strong>agentpool</strong> predeterminado. 🔧</li><li>Hacer clic en <strong>Cambiar tamaño de nodo</strong>. ⚙️</li><li>Configurar: <ul><li><strong>Recuento mínimo de nodos</strong>: <strong>1</strong>. 🔽</li><li><strong>Recuento máximo de nodos</strong>: <strong>2</strong>. 🔼</li></ul></li><li>Dejar el resto por defecto y hacer clic en <strong>Actualizar</strong>. ✅</li></ul></li><li><strong>Agregar Nuevo Grupo de Nodos</strong>: <ul><li>🆕 Hacer click en <strong>Agregar grupo de nodos</strong>.</li><li>Configurar los siguientes parámetros: <ul><li><strong>Nombre</strong>: <strong>nplinux</strong>. 🐧</li><li><strong>Modo</strong>: <strong>Usuario</strong>.</li><li><strong>Sistema operativo</strong>: <strong>Ubuntu Linux</strong>. 🐧</li><li><strong>Recuento mínimo de nodos</strong>: <strong>1</strong>. 🔽</li><li><strong>Recuento máximo de nodos</strong>: <strong>2</strong>. 🔼</li><li><strong>Tamaño del nodo</strong>: Seleccionar <strong>D2s_v3</strong> en <strong>Elegir un tamaño</strong> y hacer click en <strong>Seleccionar</strong>. ✅</li></ul></li><li>Hacer click en <strong>Agregar</strong> para crear el grupo de nodos <strong>nplinux</strong>. ➕</li></ul></li><li>Dejar los demás parámetros por defecto y seleccionar <strong>Revisar y Crear</strong>. 🔍</li></ul></li><li><p><strong>Finalizar Creación</strong>:</p><ul><li>📝 Revisar todos los detalles en la pantalla de resumen.</li><li>🟢 Hacer click en <strong>Crear</strong> para iniciar la creación del clúster.</li><li>🏁 Una vez creado, seleccionar <strong>Ir al recurso</strong> para verificar la creación. 🎉</li></ul></li></ol><h2 id="_3-conexion-al-cluster" tabindex="-1">3. Conexión al Clúster <a class="header-anchor" href="#_3-conexion-al-cluster" aria-label="Permalink to &quot;3. Conexión al Clúster&quot;">​</a></h2><ul><li><p>Abrir <strong>Cloud Shell</strong> desde el ícono en la barra superior derecha del Azure Portal.</p></li><li><p>Comando para descargar las credenciales y configurar la CLI de Kubernetes.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>az aks get-credentials --resource-group &lt;nombre-grupo-recursos&gt; --name &lt;nombre-clúster-aks&gt;</span></span></code></pre></div></li><li><p>Comando para verificar la conexión al clúster y mostrar la lista de nodos del clúster.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubectl get nodes</span></span></code></pre></div></li></ul><h2 id="_4-despliegue-de-la-aplicacion" tabindex="-1">4. Despliegue de la Aplicación <a class="header-anchor" href="#_4-despliegue-de-la-aplicacion" aria-label="Permalink to &quot;4. Despliegue de la Aplicación&quot;">​</a></h2><ul><li><p>Usar un archivo de manifiesto (<strong>aks-store-quickstart.yaml</strong>) para desplegar la aplicación AKS Store.</p></li><li><p>Guardar el archivo <strong>aks-store-quickstart.yaml</strong> en el disco local.</p></li><li><p>En Cloud Shell, seleccionar <strong>Administrar Archivos</strong> &gt; <strong>Cargar</strong> y elegir el archivo <strong>aks-store-quickstart.yaml</strong>.</p></li><li><p>Verificar que se haya cargado correctamente.</p></li><li><p>Comando para desplegar la aplicación usando el manifiesto YAML</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubectl apply -f aks-store-quickstart.yaml</span></span></code></pre></div></li></ul><h2 id="_5-prueba-de-la-aplicacion" tabindex="-1">5. Prueba de la Aplicación <a class="header-anchor" href="#_5-prueba-de-la-aplicacion" aria-label="Permalink to &quot;5. Prueba de la Aplicación&quot;">​</a></h2><ul><li><p>Comando para comprobar el estado de los pods</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubectl get pods</span></span></code></pre></div><p>Asegurarse de que todos los pods estén en estado <strong>Running</strong> antes de continuar.</p></li><li><p>Comando para obtener la <strong>IP externa</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>kubectl get service store-front --watch</span></span></code></pre></div><p>Copiar la <strong>IP externa</strong> y abrir en un navegador web para ver la aplicación AKS Store en acción.</p></li></ul><h2 id="_6-eliminacion-del-cluster" tabindex="-1">6. Eliminación del Clúster <a class="header-anchor" href="#_6-eliminacion-del-cluster" aria-label="Permalink to &quot;6. Eliminación del Clúster&quot;">​</a></h2><ul><li>Para evitar cargos innecesarios en Azure: <ol><li>En Azure Portal, ir al grupo de recursos del clúster AKS.</li><li>Seleccionar <strong>Eliminar grupo de recursos</strong>.</li><li>Ingresar el nombre del grupo de recursos y confirmae la eliminación seleccionando <strong>Eliminar</strong>.</li></ol></li></ul><h3 id="instrucciones-para-creacion-de-un-aks" tabindex="-1">Instrucciones para Creación de un AKS <a class="header-anchor" href="#instrucciones-para-creacion-de-un-aks" aria-label="Permalink to &quot;Instrucciones para Creación de un AKS&quot;">​</a></h3><p>Consultar esta guía: <a href="https://drive.google.com/file/d/1YdMylTS1FnffqImHnHVm_7u86i42vKAi/view?usp=drive_link" target="_blank">Creación de AKS</a></p>',15)])])}const h=a(s,[["render",l]]);export{p as __pageData,h as default};
